{
  "research_question": "How to verify that work history is being recorded with the correct thread ID and persisted to permanent storage when the UI or CLI cannot display it",
  "summary": "Work history should be logged in a thread‑aware manner and written to durable storage (e.g., a relational DB, document store, or append‑only log). Best practice is to embed the thread identifier in every work‑item record, use idempotent writes, and provide a back‑end query API or admin UI for inspection. Existing codebases typically expose a repository/service layer that creates WorkEntry objects with fields like `thread_id`, `timestamp`, `action`, and `payload`. Persisting via an ORM or a messaging log guarantees durability. Common pitfalls include losing the thread context when using async code, writing to in‑memory stores, or not handling write failures. Security and performance considerations revolve around preventing injection in stored payloads, limiting log size, and batching writes.",
  "best_practices": [
    {
      "practice": "Thread‑aware logging",
      "description": "Attach a unique thread identifier to every work‑history entry so that actions can be correlated across asynchronous boundaries.",
      "implementation": "Generate a UUID (or reuse the existing request/worker ID) at the start of a thread/process and propagate it via contextvars (Python) or ThreadLocal (Java). Include the ID in the data model and ensure all logging calls pull from this context.\nExample (Python):\n```python\nimport contextvars, uuid\nthread_id = contextvars.ContextVar('thread_id', default=str(uuid.uuid4()))\n\ndef start_thread():\n    token = thread_id.set(str(uuid.uuid4()))\n    try:\n        ... # work\n    finally:\n        thread_id.reset(token)\n```",
      "references": [
        "https://docs.python.org/3/library/contextvars.html",
        "https://docs.oracle.com/javase/8/docs/api/java/lang/ThreadLocal.html"
      ]
    },
    {
      "practice": "Persist to durable storage",
      "description": "Never rely solely on in‑memory structures; write each entry to a database, file, or append‑only log that survives process restarts.",
      "implementation": "Use a repository pattern with an ORM (SQLAlchemy, Django ORM, JPA) or a dedicated log service (Kafka, Cloud Pub/Sub). Ensure the write is within a transaction and handle retries on transient failures.",
      "references": [
        "https://docs.sqlalchemy.org/en/20/orm/persistence_techniques.html",
        "https://kafka.apache.org/documentation/#producerapi"
      ]
    },
    {
      "practice": "Provide an audit‑query API",
      "description": "Expose a lightweight endpoint or CLI command that can retrieve work‑history entries filtered by thread ID, time range, or action type.",
      "implementation": "Add a REST GET `/audit?thread_id=...` or a management command `spine audit --thread-id <id>` that queries the repository and returns JSON or tabular data.",
      "references": [
        "https://restfulapi.net/",
        "https://docs.djangoproject.com/en/stable/howto/custom-management-commands/"
      ]
    },
    {
      "practice": "Idempotent and atomic writes",
      "description": "Guarantee that duplicate entries cannot be created if a retry occurs.",
      "implementation": "Add a unique constraint on (`thread_id`, `timestamp`, `action_hash`) and use upsert semantics (ON CONFLICT DO NOTHING).",
      "references": [
        "https://www.postgresql.org/docs/current/sql-insert.html#SQL-ON-CONFLICT"
      ]
    }
  ],
  "existing_patterns": [
    {
      "location": "src/spine/models/work_entry.py",
      "pattern": "SQLAlchemy model `WorkEntry` with fields `id`, `thread_id`, `timestamp`, `action`, `payload`",
      "relevance": "Shows the current data structure used for persisting work history; can be extended to include a proper thread ID."
    },
    {
      "location": "src/spine/services/audit_service.py",
      "pattern": "Repository pattern exposing `record_action(thread_id, action, payload)`",
      "relevance": "Provides the central place to ensure every audit entry passes through the same validation and persistence logic."
    },
    {
      "location": "src/spine/cli/audit.py",
      "pattern": "Click command `audit` that currently reads from an in‑memory cache only",
      "relevance": "Needs to be updated to query the permanent store instead of the volatile cache."
    }
  ],
  "recommended_approach": {
    "approach": "Introduce a Thread‑Context aware Audit Service with persistent storage and an admin query API",
    "rationale": "Combines proven patterns (context propagation, repository, idempotent writes) while giving operators a way to verify the data without UI/CLI reliance on volatile caches.",
    "steps": [
      "1. Define a `thread_id` ContextVar (Python) or ThreadLocal (Java) and set it at the start of each request/worker.",
      "2. Extend `WorkEntry` model to require `thread_id` (non‑null) and add a unique constraint for idempotency.",
      "3. Update `AuditService.record_action` to read the current `thread_id` from context and persist via the repository inside a transaction.",
      "4. Implement a new CLI command `spine audit --thread-id <id>` and a corresponding REST endpoint that queries the DB.",
      "5. Add unit and integration tests verifying that:",
      "   - The same thread ID appears on all entries for a given request.",
      "   - Entries survive process restart.",
      "   - Duplicate writes are prevented.",
      "6. Deploy migration to add the `thread_id` column and constraints to existing tables."
    ],
    "alternatives_considered": [
      {
        "approach": "Log to flat files and parse them on demand",
        "rejected_because": "File parsing is brittle, lacks atomicity, and makes queries inefficient; does not integrate well with existing ORM‑based code."
      },
      {
        "approach": "Rely on external observability platform (e.g., Datadog) only",
        "rejected_bbecause": "Observability data may be retained only for a limited window and is not under our control for audits requiring long‑term retention."
      }
    ]
  },
  "pitfalls": [
    {
      "pitfall": "Losing thread context in async code",
      "why": "Async tasks may switch execution contexts, causing the thread ID to be lost or overwritten.",
      "prevention": "Use `contextvars` (Python 3.7+) which propagates automatically across async calls; avoid global variables."
    },
    {
      "pitfall": "Writing to an in‑memory cache instead of the DB",
      "why": "Data disappears on restart, breaking auditability.",
      "prevention": "Ensure the repository layer points to the persistent engine; add integration tests that restart the process and verify data persists."
    },
    {
      "pitfall": "Unbounded growth of audit tables",
      "why": "Can degrade performance and increase storage costs.",
      "prevention": "Implement retention policies (e.g., archive older entries to cold storage) and add indexes on `thread_id` and `timestamp`."
    },
    {
      "pitfall": "Storing raw user payloads without sanitization",
      "why": "May lead to injection attacks when payloads are later displayed or re‑processed.",
      "prevention": "Validate and, if necessary, encode payloads; store as JSONB with schema validation."
    }
  ],
